{
  "title": "Exploring the Taungoo Empire: A Historical Journey",
  "description": "This course provides a comprehensive overview of the Taungoo Empire, focusing on its founding, significant achievements, and the roles of women in its society. Designed for learners with little prior knowledge, the course will guide participants through the empire's history and contributions to the region.",
  "modules": [
    {
      "id": "module1",
      "title": "Foundations of the Taungoo Empire",
      "description": "An introduction to the origins and establishment of the Taungoo Empire, exploring the historical context and key figures involved in its founding."
    },
    {
      "id": "module2",
      "title": "Significant Achievements of the Taungoo Empire",
      "description": "A detailed examination of the major accomplishments of the Taungoo Empire, including military conquests, cultural advancements, and economic developments."
    },
    {
      "id": "module3",
      "title": "Women in the Taungoo Empire",
      "description": "An exploration of the roles and contributions of women in the Taungoo Empire, highlighting influential figures and their impact on society."
    },
    {
      "id": "module4",
      "title": "Legacy and Influence of the Taungoo Empire",
      "description": "A discussion on the lasting effects of the Taungoo Empire on modern Myanmar and Southeast Asia, including cultural and historical legacies."
    }
  ]
}
